const now = new Date();
const month = now.toLocaleString('default', { month: 'long' });
const year = now.getFullYear();

// Parse RSS/API responses
const mcpServers = $input.first().json.items || [];
const n8nIntegrations = $input.all()[1].json.items || [];
const cursorUpdates = $input.all()[2].json.releases || [];

// Filter for relevant/new items (example logic)
const relevantMCP = mcpServers.filter(s => 
  s.tags?.includes('github') || 
  s.tags?.includes('knowledge') || 
  s.tags?.includes('automation')
).slice(0, 10);

const issueBody = `
# Monthly Tool Ecosystem Review - ${month} ${year}

> **Auto-generated** by HeliOS-Studio monitoring workflow  
> **Due:** End of this week  

## Checklist

### MCP Servers

- [ ] Review [PulseMCP.com/servers](https://www.pulsemcp.com/servers) for new servers
- [ ] Check if any of these new servers are relevant:

${relevantMCP.map(s => `  - **${s.name}**: ${s.description} ([link](${s.url}))`).join('\n')}

- [ ] Test existing MCP servers still work:
  - [ ] n8n MCP server
  - [ ] NotebookLM MCP server (unofficial)
  - [ ] Obsidian MCP server
  - [ ] GitHub MCP server

### Tool Updates

- [ ] Review n8n integrations page for new native nodes
- [ ] Check Cursor release notes: ${cursorUpdates.length} updates this month
- [ ] Check Claude Desktop / Claude Code announcements
- [ ] Check NotebookLM feature releases

### Documentation

- [ ] Update [INTEGRATIONS.md](../docs/INTEGRATIONS.md) with new capabilities
- [ ] Update [PROJECT_MANAGEMENT.md](../docs/PROJECT_MANAGEMENT.md) if PM tools changed
- [ ] Update \`LAST_REVIEWED\` date in INTEGRATIONS.md

### Testing

- [ ] Run end-to-end test: Perplexity → NotebookLM → Claude → GitHub
- [ ] Verify all n8n workflows still execute
- [ ] Check GitHub Projects automation still works

## Notes

Add observations, breaking changes, or recommendations below:

---

**Auto-assigned to:** @zebadee2kk
`;

return {
  json: {
    title: `Monthly Tool Review - ${month} ${year}`,
    body: issueBody,
    labels: ['maintenance', 'ecosystem-review', 'automated'],
    assignees: ['zebadee2kk']
  }
};
